SELECT table_name, population_type
FROM life_tables
WHERE region = 'North America';

SELECT COUNT(*) AS count_in_age_range
FROM life_tables
WHERE age_range = '30-39' AND population_type = 'general population';

SELECT COUNT(DISTINCT policyholder_id) AS total_policyholders
FROM policyholder_life_table_link
WHERE link_date BETWEEN '2022-01-01' AND '2022-12-31';

SELECT life_table_id, COUNT(policyholder_id) AS policyholder_count
FROM policyholder_life_table_link
GROUP BY life_table_id;

SELECT population_type, COUNT(*) AS life_table_count
FROM life_tables
GROUP BY population_type;

SELECT AVG(ex) AS average_life_expectancy
FROM life_tables
WHERE age_range = '70-79' AND life_table_id = '0';

SELECT COUNT(*) AS policyholder_count
FROM policyholders
WHERE age BETWEEN 30 AND 40 AND gender = 'Male';

SELECT COUNT(*) AS Number_of_Policyholders
FROM policyholder_life_table_link
WHERE link_date BETWEEN '2022-01-01' AND '2023-01-01';

SELECT COUNT(*) AS total_policyholders_linked_to_life_table
FROM policyholder_life_table_link
WHERE link_date > '2021-12-31';

SELECT last_updated, population_type
FROM life_tables
WHERE life_table_id = '0';

SELECT gender, COUNT(*) AS number_of_policyholders
FROM policyholders
GROUP BY gender;

SELECT AVG(ex) AS average_life_expectancy
FROM life_tables
WHERE region = 'North America';

SELECT table_name
FROM life_tables
WHERE ex = (SELECT MAX(ex) FROM life_tables);
